<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();

function ss_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function ss_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ss_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function ss_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function ss_c($v){return strtoupper(trim((string)$v));}
function ss_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function ss_date_ok($v){return (bool)preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$v);}
function ss_time($v){$v=trim((string)$v);if($v==='')return null;if(preg_match('/^\d{2}:\d{2}$/',$v))return $v.':00';if(preg_match('/^\d{2}:\d{2}:\d{2}$/',$v))return $v;ss_json('error','Format jam harus HH:MM atau HH:MM:SS.');}
function ss_num($v){return is_numeric($v)?(float)$v:0;}
function ss_int($v){return is_numeric($v)?(int)$v:0;}
function ss_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function ss_row($id){global $db;return $db->fetch("SELECT ss.*,e.full_name,e.employee_group,e.employment_status,d.nm_dept,d.dept_type,ws.schedule_name,wl.location_code,wl.location_name,wl.location_type,s.nama_shift,s.jam_mulai,s.jam_selesai FROM erp_shift_schedule ss JOIN erp_employee_master e ON e.id=ss.employee_id LEFT JOIN dept d ON d.kd_dept=ss.department_code LEFT JOIN erp_work_schedule ws ON ws.id=ss.work_schedule_id LEFT JOIN erp_work_location wl ON wl.id=ss.work_location_id LEFT JOIN erp_shift s ON s.id=ss.shift_id WHERE ss.id=? LIMIT 1",array((int)$id));}
function ss_payload($r){$d=(array)$r;$d['employee_text']=$r->employee_id?($r->employee_no.' - '.$r->full_name.' ['.$r->employment_status.']'):'';$d['department_text']=$r->department_code?($r->department_code.' - '.$r->nm_dept.' ['.$r->dept_type.']'):'';$d['work_schedule_text']=$r->work_schedule_id?($r->work_schedule_code.' - '.$r->schedule_name):'';$d['shift_text']=$r->shift_id?($r->shift_code.' - '.$r->nama_shift.' ('.substr($r->jam_mulai,0,5).'-'.substr($r->jam_selesai,0,5).')'):'';$d['work_location_text']=$r->work_location_id?($r->location_code.' - '.$r->location_name.' ['.$r->location_type.']'):'';$d['planned_start']=$r->planned_start?substr($r->planned_start,0,5):'';$d['planned_end']=$r->planned_end?substr($r->planned_end,0,5):'';return $d;}
function ss_rows($from,$to,$emp,$dept,$shift,$status,$roster,$kw){global $db;$w=" WHERE ss.schedule_from<=? AND ss.schedule_to>=? ";$p=array($to,$from);if($emp!==''){$w.=" AND ss.employee_id=? ";$p[]=(int)$emp;}if($dept!==''){$w.=" AND ss.department_code=? ";$p[]=$dept;}if($shift!==''){$w.=" AND ss.shift_id=? ";$p[]=(int)$shift;}if($status!==''){$w.=" AND ss.assignment_status=? ";$p[]=$status;}if($roster!==''){$w.=" AND ss.roster_type=? ";$p[]=$roster;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (ss.assignment_no LIKE ? OR ss.employee_no LIKE ? OR e.full_name LIKE ? OR ss.rotation_group LIKE ? OR ss.sap_reference LIKE ? OR ss.remarks LIKE ?) ";array_push($p,$like,$like,$like,$like,$like,$like);}return $db->query("SELECT ss.*,e.full_name,e.employee_group,e.employment_status,d.nm_dept,ws.schedule_name,wl.location_code,wl.location_name,s.nama_shift,s.jam_mulai,s.jam_selesai FROM erp_shift_schedule ss JOIN erp_employee_master e ON e.id=ss.employee_id LEFT JOIN dept d ON d.kd_dept=ss.department_code LEFT JOIN erp_work_schedule ws ON ws.id=ss.work_schedule_id LEFT JOIN erp_work_location wl ON wl.id=ss.work_location_id LEFT JOIN erp_shift s ON s.id=ss.shift_id $w ORDER BY ss.schedule_from DESC,ss.assignment_no",$p);}
$act=isset($_GET['act'])?$_GET['act']:'';$username=ss_user();
