switch($act){
case 'employee_search':$t=trim(ss_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,employee_no,full_name,department_code,employee_group,employment_status FROM erp_employee_master WHERE employment_status IN ('ACTIVE','PROBATION','CONTRACT') AND (?='' OR employee_no LIKE ? OR full_name LIKE ? OR department_code LIKE ?) ORDER BY employee_no LIMIT 30",array($t,$like,$like,$like));ss_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name.' ['.$r->department_code.' / '.$r->employee_group.']';});
case 'department_search':$t=trim(ss_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT kd_dept,nm_dept,dept_type FROM dept WHERE status='ACTIVE' AND (?='' OR kd_dept LIKE ? OR nm_dept LIKE ? OR dept_type LIKE ?) ORDER BY kd_dept LIMIT 30",array($t,$like,$like,$like));ss_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept.' ['.$r->dept_type.']';});
case 'shift_search':$t=trim(ss_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,kode_shift,nama_shift,jam_mulai,jam_selesai FROM erp_shift WHERE status='Aktif' AND (?='' OR kode_shift LIKE ? OR nama_shift LIKE ?) ORDER BY kode_shift LIMIT 30",array($t,$like,$like));ss_select2($rows,'id',function($r){return $r->kode_shift.' - '.$r->nama_shift.' ('.substr($r->jam_mulai,0,5).'-'.substr($r->jam_selesai,0,5).')';});
case 'work_schedule_search':$t=trim(ss_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,schedule_code,schedule_name,schedule_category,department_code FROM erp_work_schedule WHERE schedule_status='ACTIVE' AND (?='' OR schedule_code LIKE ? OR schedule_name LIKE ? OR schedule_category LIKE ? OR department_code LIKE ?) ORDER BY schedule_category,schedule_code LIMIT 30",array($t,$like,$like,$like,$like));ss_select2($rows,'id',function($r){return $r->schedule_code.' - '.$r->schedule_name.' ['.$r->schedule_category.' / '.($r->department_code?:'-').']';});
case 'work_location_search':$t=trim(ss_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,location_code,location_name,location_type,city FROM erp_work_location WHERE status='ACTIVE' AND (?='' OR location_code LIKE ? OR location_name LIKE ? OR location_type LIKE ? OR city LIKE ?) ORDER BY location_type,location_code LIMIT 30",array($t,$like,$like,$like,$like));ss_select2($rows,'id',function($r){return $r->location_code.' - '.$r->location_name.' ['.$r->location_type.($r->city?' / '.$r->city:'').']';});
