case 'get':$r=ss_row((int)ss_p('id'));if(!$r)ss_json('error','Shift Schedule tidak ditemukan.');ss_json('good','',array('data'=>ss_payload($r)));
case 'save':
  $id=(int)ss_p('id');$no=ss_c(ss_p('assignment_no'));$emp=(int)ss_p('employee_id');$shift=(int)ss_p('shift_id');$from=trim(ss_p('schedule_from'));$to=trim(ss_p('schedule_to'));$status=ss_c(ss_p('assignment_status','DRAFT'));$roster=ss_c(ss_p('roster_type','REGULAR'));$source=ss_c(ss_p('source_type','MANUAL'));
