  $days=array('monday','tuesday','wednesday','thursday','friday','saturday','sunday');$dayData=array();foreach($days as $d){$v=ss_c(ss_p($d,'N'));if(!in_array($v,$yn,true))ss_json('error','Working day '.$d.' tidak valid.');$dayData[$d]=$v;}
  $e=$db->fetch("SELECT id,employee_no,department_code FROM erp_employee_master WHERE id=? LIMIT 1",array($emp));if(!$e)ss_json('error','Employee tidak valid.');$sh=$db->fetch("SELECT id,kode_shift FROM erp_shift WHERE id=? LIMIT 1",array($shift));if(!$sh)ss_json('error','Shift tidak valid.');
  $dept=ss_p('department_code')!==''?ss_c(ss_p('department_code')):$e->department_code;if($dept&&!$db->fetch("SELECT kd_dept FROM dept WHERE kd_dept=? LIMIT 1",array($dept)))ss_json('error','Department tidak valid.');
  $wsId=ss_p('work_schedule_id')!==''?(int)ss_p('work_schedule_id'):null;$wsCode=null;if($wsId){$ws=$db->fetch("SELECT id,schedule_code FROM erp_work_schedule WHERE id=? LIMIT 1",array($wsId));if(!$ws)ss_json('error','Work Schedule tidak valid.');$wsCode=$ws->schedule_code;}
  $locId=ss_p('work_location_id')!==''?(int)ss_p('work_location_id'):null;if($locId&&!$db->fetch("SELECT id FROM erp_work_location WHERE id=? LIMIT 1",array($locId)))ss_json('error','Work Location tidak valid.');
