  $data=array_merge(array('assignment_no'=>$no,'employee_id'=>$emp,'employee_no'=>$e->employee_no,'department_code'=>$dept,'work_schedule_id'=>$wsId,'work_schedule_code'=>$wsCode,'shift_id'=>$shift,'shift_code'=>$sh->kode_shift,'work_location_id'=>$locId,'schedule_from'=>$from,'schedule_to'=>$to),$dayData,array('planned_start'=>ss_time(ss_p('planned_start')),'planned_end'=>ss_time(ss_p('planned_end')),'break_minutes'=>$break,'planned_hours_per_day'=>$hours,'rotation_group'=>trim(ss_p('rotation_group')),'roster_type'=>$roster,'source_type'=>$source,'overtime_eligible'=>$ot,'attendance_required'=>$att,'assignment_status'=>$status,'sap_reference'=>trim(ss_p('sap_reference')),'remarks'=>trim(ss_p('remarks')),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')));
